// getBidiClassFromData returns the BidiClass for a rune using binary search
func getBidiClassFromData(r rune) BidiClass {
	left, right := 0, len(bidiData)-1
	for left <= right {
		mid := (left + right) / 2
		entry := bidiData[mid]
		if r < entry.start {
			right = mid - 1
		} else if r > entry.end {
			left = mid + 1
		} else {
			return entry.class
		}
	}
	return ClassL // Default to Left-to-Right
}
